#include<iostream>#include<vector>#include<algorithm>#include<unordered_map>#include<climits>#define ll long longusing namespace std;int main(){    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> arr(n);                for(int i=0;i<n;i++){            cin>>arr[i];          }        vector<ll> a(n);        a=arr;        sort(a.begin(),a.end());        if(a==arr){            cout<<n<<"\n";        }        else{            cout<<1<<"\n";        }    }}